import{_ as o,o as r,c as i,a0 as t}from"./chunks/framework.CSGB4SNl.js";const l=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"drone-pro/drone-user-uni/uni_modules/uni-forms/readme.md","filePath":"drone-pro/drone-user-uni/uni_modules/uni-forms/readme.md"}'),n={name:"drone-pro/drone-user-uni/uni_modules/uni-forms/readme.md"};function d(u,e,c,a,s,m){return r(),i("div",null,[...e[0]||(e[0]=[t('<h2 id="forms-表单" tabindex="-1">Forms 表单 <a class="header-anchor" href="#forms-表单" aria-label="Permalink to &quot;Forms 表单&quot;">​</a></h2><blockquote><p><strong>组件名：uni-forms</strong> 代码块： <code>uForms</code>、<code>uni-forms-item</code> 关联组件：<code>uni-forms-item</code>、<code>uni-easyinput</code>、<code>uni-data-checkbox</code>、<code>uni-group</code>。</p></blockquote><p>uni-app的内置组件已经有了 <code>&lt;form&gt;</code>组件，用于提交表单内容。</p><p>然而几乎每个表单都需要做表单验证，为了方便做表单验证，减少重复开发，<code>uni ui</code> 又基于 <code>&lt;form&gt;</code>组件封装了 <code>&lt;uni-forms&gt;</code>组件，内置了表单验证功能。</p><p><code>&lt;uni-forms&gt;</code> 提供了 <code>rules</code>属性来描述校验规则、<code>&lt;uni-forms-item&gt;</code>子组件来包裹具体的表单项，以及给原生或三方组件提供了 <code>binddata()</code> 来设置表单值。</p><p>每个要校验的表单项，不管input还是checkbox，都必须放在<code>&lt;uni-forms-item&gt;</code>组件中，且一个<code>&lt;uni-forms-item&gt;</code>组件只能放置一个表单项。</p><p><code>&lt;uni-forms-item&gt;</code>组件内部预留了显示error message的区域，默认是在表单项的底部。</p><p>另外，<code>&lt;uni-forms&gt;</code>组件下面的各个表单项，可以通过<code>&lt;uni-group&gt;</code>包裹为不同的分组。同一<code>&lt;uni-group&gt;</code>下的不同表单项目将聚拢在一起，同其他group保持垂直间距。<code>&lt;uni-group&gt;</code>仅影响视觉效果。</p><h3 id="查看文档" tabindex="-1"><a href="https://uniapp.dcloud.io/component/uniui/uni-forms" target="_blank" rel="noreferrer">查看文档</a> <a class="header-anchor" href="#查看文档" aria-label="Permalink to &quot;[查看文档](https://uniapp.dcloud.io/component/uniui/uni-forms)&quot;">​</a></h3><h4 id="如使用过程中有任何问题-或者您对uni-ui有一些好的建议-欢迎加入-uni-ui-交流群-871950839" tabindex="-1">如使用过程中有任何问题，或者您对uni-ui有一些好的建议，欢迎加入 uni-ui 交流群：871950839 <a class="header-anchor" href="#如使用过程中有任何问题-或者您对uni-ui有一些好的建议-欢迎加入-uni-ui-交流群-871950839" aria-label="Permalink to &quot;如使用过程中有任何问题，或者您对uni-ui有一些好的建议，欢迎加入 uni-ui 交流群：871950839&quot;">​</a></h4>',10)])])}const f=o(n,[["render",d]]);export{l as __pageData,f as default};
